#include <math.h>

int main() {
    int x;
    scanf("%d", &x);
    int y = 1;
    int k = 1;
    int bea[100];
    int index = 0;
    while (y <= 100000) {
        y = (pow(2, k) - 1) * pow(2, k - 1);
        bea[index++] = y;
        k = k + 1;
    }
    index--;
    int temp = 0;
    for (int j = 0; j < index; j++) {
        if (x % bea[j] == 0) {
            temp = bea[j];
        }
    }
    printf("%d", temp);
    return 0;
}
